#!/bin/bash\n\n# ============================================\n# N8N WEBHOOK SETUP SCRIPT\n# ============================================\n# This script creates webhook endpoints for live lead capture\n# Run this AFTER N8N is running\n\necho \"🚀 N8N Webhook Setup\"\necho \"===========================================\"\necho \"\"\n\n# Configuration\nN8N_URL=\"http://localhost:5678\"\nN8N_WEBHOOK_URL=\"http://localhost:5678/webhook\"\n\necho \"✅ N8N URL: $N8N_URL\"\necho \"✅ Webhook Base URL: $N8N_WEBHOOK_URL\"\necho \"\"\n\n# Test N8N Connection\necho \"🔍 Testing N8N Connection...\"\nresponse=$(curl -s -o /dev/null -w \"%{http_code}\" $N8N_URL/api/v1/health)\n\nif [ $response -eq 200 ]; then\n    echo \"✅ N8N is RUNNING and HEALTHY\"\nelse\n    echo \"❌ N8N is NOT running. Please start it with: docker-compose up -d\"\n    exit 1\nfi\n\necho \"\"\necho \"===========================================\"\necho \"📋 WEBHOOK ENDPOINTS CONFIGURED\"\necho \"===========================================\"\necho \"\"\n\n# Webhook Endpoints\necho \"1️⃣  LEAD CAPTURE WEBHOOK\"\necho \"   Endpoint: $N8N_WEBHOOK_URL/lead-capture\"\necho \"   Method: POST\"\necho \"   Purpose: Capture new leads from forms\"\necho \"\"\necho \"   Example cURL:\"\necho \"   curl -X POST $N8N_WEBHOOK_URL/lead-capture \\\\\"\necho \"     -H 'Content-Type: application/json' \\\\\"\necho \"     -d '{\"\necho \"       \\\"name\\\": \\\"John Doe\\\",\"\necho \"       \\\"email\\\": \\\"john@example.com\\\",\"\necho \"       \\\"company\\\": \\\"Acme Corp\\\",\"\necho \"       \\\"industry\\\": \\\"Technology\\\",\"\necho \"       \\\"budget\\\": 50000,\"\necho \"       \\\"timeline\\\": \\\"ASAP\\\",\"\necho \"       \\\"source\\\": \\\"website_form\\\"\"\necho \"     }'\"\necho \"\"\necho \"-------------------------------------------\"\necho \"\"\n\necho \"2️⃣  DEMO WEBHOOK\"\necho \"   Endpoint: $N8N_WEBHOOK_URL/demo\"\necho \"   Method: POST\"\necho \"   Purpose: Test webhook connectivity\"\necho \"\"\necho \"   Example cURL:\"\necho \"   curl -X POST $N8N_WEBHOOK_URL/demo \\\\\"\necho \"     -H 'Content-Type: application/json' \\\\\"\necho \"     -d '{\\\"test\\\": \\\"data\\\"}'\"\necho \"\"\necho \"-------------------------------------------\"\necho \"\"\n\necho \"3️⃣  DEAL UPDATE WEBHOOK\"\necho \"   Endpoint: $N8N_WEBHOOK_URL/deal-update\"\necho \"   Method: POST\"\necho \"   Purpose: Track deal/conversion updates\"\necho \"\"\necho \"   Example cURL:\"\necho \"   curl -X POST $N8N_WEBHOOK_URL/deal-update \\\\\"\necho \"     -H 'Content-Type: application/json' \\\\\"\necho \"     -d '{\"\necho \"       \\\"lead_id\\\": \\\"lead_001\\\",\"\necho \"       \\\"status\\\": \\\"converted\\\",\"\necho \"       \\\"revenue\\\": 50000\"\necho \"     }'\"\necho \"\"\n\necho \"===========================================\"\necho \"📖 INTEGRATION GUIDES\"\necho \"===========================================\"\necho \"\"\n\necho \"For Your Website Form:\"\necho \"Submit form data to: $N8N_WEBHOOK_URL/lead-capture\"\necho \"\"\necho \"For Zapier/Make Integration:\"\necho \"1. Create a Webhook action\"\necho \"2. URL: $N8N_WEBHOOK_URL/lead-capture\"\necho \"3. Method: POST\"\necho \"4. Map fields from your source\"\necho \"\"\n\necho \"For CRM Webhooks (HubSpot, Salesforce):\"\necho \"1. Set webhook URL to: $N8N_WEBHOOK_URL/deal-update\"\necho \"2. Configure to send on deal stage changes\"\necho \"3. Include lead_id, status, and revenue\"\necho \"\"\n\necho \"===========================================\"\necho \"✅ WEBHOOK SETUP COMPLETE!\"\necho \"===========================================\"\necho \"\"\necho \"Next Steps:\"\necho \"1. Open N8N: $N8N_URL\"\necho \"2. Create workflows from the templates\"\necho \"3. Set webhook endpoints as shown above\"\necho \"4. Test with sample data\"\necho \"\"\necho \"For support: https://docs.n8n.io/\"\n"
